/* Aula 33 — modelJs: lista + detalhe (state + render + delegation) */

const reloadBtn = document.querySelector('#reload');
const statusEl = document.querySelector('#status');
const listaEl = document.querySelector('#lista');
const detalhesEl = document.querySelector('#detalhes');

let state = {
  users: [],
  selectedId: null,
  loading: false,
  error: ''
};

async function requestJSON(url) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return await res.json();
}

function render() {
  // status
  if (statusEl) {
    if (state.loading) statusEl.textContent = 'Carregando...';
    else if (state.error) statusEl.textContent = `Erro: ${state.error}`;
    else statusEl.textContent = state.users.length ? 'OK' : 'Vazio';
  }

  // lista
  if (listaEl) {
    listaEl.innerHTML = '';

    for (const u of state.users) {
      const li = document.createElement('li');
      li.className = 'item';
      li.dataset.id = String(u.id);

      if (u.id === state.selectedId) li.classList.add('ativo');

      const strong = document.createElement('strong');
      strong.textContent = u.name;

      const email = document.createElement('span');
      email.className = 'muted';
      email.textContent = u.email;

      const box = document.createElement('div');
      box.className = 'stack';
      box.append(strong, email);

      li.appendChild(box);
      listaEl.appendChild(li);
    }
  }

  // detalhes
  if (detalhesEl) {
    detalhesEl.innerHTML = '';

    const u = state.users.find(x => x.id === state.selectedId);
    if (!u) {
      detalhesEl.textContent = state.users.length ? 'Selecione um usuário' : 'Sem dados';
      return;
    }

    const nome = document.createElement('h3');
    nome.textContent = u.name;

    const info = document.createElement('p');
    info.className = 'muted';
    info.textContent = `${u.email} • ${u.phone}`;

    const empresa = document.createElement('p');
    empresa.textContent = `Empresa: ${u.company?.name || '-'}`;

    detalhesEl.append(nome, info, empresa);
  }
}

async function carregarLista() {
  state.loading = true;
  state.error = '';
  render();

  try {
    const users = await requestJSON('https://jsonplaceholder.typicode.com/users');
    state.users = users;
    state.selectedId = users.length ? users[0].id : null;
  } catch (err) {
    state.error = err.message;
    state.users = [];
    state.selectedId = null;
  } finally {
    state.loading = false;
    render();
  }
}

if (reloadBtn) reloadBtn.addEventListener('click', carregarLista);

if (listaEl) {
  listaEl.addEventListener('click', (e) => {
    const item = e.target.closest('.item');
    if (!item) return;
    state.selectedId = Number(item.dataset.id);
    render();
  });
}

carregarLista();
